/*!id: jdt-internal-field-to-getter*/
/*!description: Refactor internal JDT compiler AST classes to use getter methods instead of direct field access.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/

// StringLiteralConcatenation.literals -> .getLiterals()
$literal.literals :: instanceof($literal, "org.eclipse.jdt.internal.compiler.ast.StringLiteralConcatenation")
=> $literal.getLiterals()
;;

// StringLiteral.source -> .source()
$expression.source :: instanceof($expression, "org.eclipse.jdt.internal.compiler.ast.StringLiteral")
=> $expression.source()
;;

// Replace direct field access with getter for StringLiteralConcatenation.literals
$literal.literals :: instanceof($literal, "org.eclipse.jdt.internal.compiler.ast.StringLiteralConcatenation")
=> $literal.getLiterals()
;;

// Replace direct field access with getter for StringLiteral.source
$stringLiteral.source :: instanceof($stringLiteral, "org.eclipse.jdt.internal.compiler.ast.StringLiteral")
=> $stringLiteral.source()
;;

// Replace direct field access with length of getter result for StringLiteralConcatenation.counter
$literal.counter :: instanceof($literal, "org.eclipse.jdt.internal.compiler.ast.StringLiteralConcatenation")
=> $literal.getLiterals().length
;;

// Remove redundant cast to IBinaryType for getElementInfo() on BinaryType
(org.eclipse.jdt.internal.compiler.env.IBinaryType) $binaryType.getElementInfo() :: instanceof($binaryType, "org.eclipse.jdt.internal.core.BinaryType")
=> $binaryType.getElementInfo()
;;

/*!id: jdt-remove-redundant-astnode-cast*/
/*!description: Remove redundant (ASTNode) casts when the expression is already an ASTNode subtype.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring, performance*/
(org.eclipse.jdt.core.dom.ASTNode) $expression :: subtypeOf($expression, "org.eclipse.jdt.core.dom.ASTNode")
=> $expression
;;

/*!id: jdt-remove-redundant-typedec-cast*/
/*!description: Remove redundant (TypeDeclaration) cast when the expression is already proven to be of that type by context (e.g., instanceof guard).*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring, performance*/
(org.eclipse.jdt.core.dom.TypeDeclaration) $var :: subtypeOf($var, "org.eclipse.jdt.core.dom.TypeDeclaration")
=> $var
;;

/*!id: jdt-remove-redundant-annotypedec-cast*/
/*!description: Remove redundant (AnnotationTypeDeclaration) cast when the expression is already proven to be of that type by context (e.g., instanceof guard).*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring, performance*/
(org.eclipse.jdt.core.dom.AnnotationTypeDeclaration) $var :: subtypeOf($var, "org.eclipse.jdt.core.dom.AnnotationTypeDeclaration")
=> $var
;;

// Remove redundant (ASTNode) cast before clone(target) calls on JDT AST nodes
(org.eclipse.jdt.core.dom.ASTNode) $expr.clone($target)
=> $expr.clone($target)
;;

// Remove redundant casts to TypeDeclaration before resolveBinding() if already known to be TypeDeclaration
((org.eclipse.jdt.core.dom.TypeDeclaration) $d).resolveBinding() :: instanceof($d, "org.eclipse.jdt.core.dom.TypeDeclaration")
=> $d.resolveBinding()
;;

// Remove redundant casts to AnnotationTypeDeclaration before resolveBinding() if already known to be AnnotationTypeDeclaration
((org.eclipse.jdt.core.dom.AnnotationTypeDeclaration) $d).resolveBinding() :: instanceof($d, "org.eclipse.jdt.core.dom.AnnotationTypeDeclaration")
=> $d.resolveBinding()
;;

/*!id: jdt-internal-astrequestor-resolver*/
/*!description: Refactors ASTRequestor to use Function for binding resolution, replacing direct CompilationUnitResolver access. Updates field references and method calls to align with internal API change.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/

// Replace method invocation: this.compilationUnitResolver.createBinding($bindingKey) -> this.additionalBindingResolver.apply($bindingKey)
@id: jdt.internal.astrequestor.createBinding.to.apply
this.compilationUnitResolver.createBinding($bindingKey)
=> this.additionalBindingResolver.apply($bindingKey)
;;

// Replace assignment: $astRequestor.compilationUnitResolver = this -> $astRequestor.additionalBindingResolver = this::createBinding
@id: jdt.internal.astrequestor.assign.this.to.methodref
$astRequestor.compilationUnitResolver = this
=> $astRequestor.additionalBindingResolver = this::createBinding
;;

// Replace assignment: $astRequestor.compilationUnitResolver = null -> $astRequestor.additionalBindingResolver = null
@id: jdt.internal.astrequestor.assign.null
$astRequestor.compilationUnitResolver = null
=> $astRequestor.additionalBindingResolver = null
;;

/*!id: jdt.internal.bindingresolver.remove-bogus-subarray*/
/*!description: Removes redundant CharOperation.subarray(array, 0, array.length) calls which are equivalent to using the array directly, improving clarity and efficiency.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring, performance*/
org.eclipse.jdt.internal.compiler.util.CharOperation.subarray($array, 0, $array.length)
=> $array
;;

/*!id: jdt.internal.bindingresolver.isstatic-to-modifiers-localvar-subarray*/
/*!description: Replaces the 'isStatic' boolean local variable and removes the bogus CharOperation.subarray() call in Scope.getImport, modernizing API usage to 'importReference.modifiers'.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
this.scope.getImport(org.eclipse.jdt.internal.compiler.util.CharOperation.subarray($importReference.tokens, 0, $importReference.tokens.length), true, isStatic)
=> this.scope.getImport($importReference.tokens, true, $importReference.modifiers)
;;

/*!id: jdt.internal.bindingresolver.isstatic-to-modifiers-localvar*/
/*!description: Replaces the 'isStatic' boolean local variable with 'importReference.modifiers' in Scope.getImport method calls, reflecting internal API modernization.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
this.scope.getImport($importReference.tokens, false, isStatic)
=> this.scope.getImport($importReference.tokens, false, $importReference.modifiers)
;;

/*!id: jdt.internal.bindingresolver.isstatic-methodcall-to-modifiers*/
/*!description: Replaces 'importReference.isStatic()' method call with 'importReference.modifiers' field in Scope.getImport calls, reflecting internal API modernization from boolean flag to int bitmask.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
org.eclipse.jdt.internal.compiler.lookup.Scope.getImport($tokens, $onDemand, $importReference.isStatic())
=> org.eclipse.jdt.internal.compiler.lookup.Scope.getImport($tokens, $onDemand, $importReference.modifiers)
;;

// Modernize internal JDT AST level check in internalSet method
// Replaces an explicit, potentially always-false, range check with a more robust check against the new ALL_VERSIONS list.
@id: jdt.internal.ast.level-check-modernization-internalset
$level < org.eclipse.jdt.core.dom.AST.JLS2_INTERNAL && $level > org.eclipse.jdt.core.dom.AST.JLS_Latest
=> !org.eclipse.jdt.core.dom.AST.ALL_VERSIONS.contains($level)
;;

// Modernize internal JDT AST level check in getCompliance method
// Replaces an explicit, potentially always-false, range check with a more robust check against the new ALL_VERSIONS list.
@id: jdt.internal.ast.level-check-modernization-getcompliance
$astLevel < org.eclipse.jdt.core.dom.AST.JLS2 && $astLevel > org.eclipse.jdt.core.dom.AST.getJLSLatest()
=> !org.eclipse.jdt.core.dom.AST.getAllVersions().contains($astLevel)
;;

