/*!id: jdt.internal.astmatcher.typepattern.getpatternvariable-to-getpatternvariable2*/
/*!description: Modernize ASTMatcher logic for TypePattern to use getPatternVariable2() for JLS22+ to reflect API evolution.*/
/*!severity: info*/
/*!minJavaVersion: 16*/
safeSubtreeMatch($node.getPatternVariable(), $o.getPatternVariable()) :: instanceof($node, "org.eclipse.jdt.core.dom.TypePattern") && instanceof($o, "org.eclipse.jdt.core.dom.TypePattern") && sourceVersionGE(22)
=> safeSubtreeMatch($node.getPatternVariable2(), $o.getPatternVariable2())
;;

/*!id: jdt.internal.astmatcher.typepattern.getpatternvariable-to-getpatternvariable2*/
/*!description: Modernize ASTMatcher logic for TypePattern to use getPatternVariable2() for JLS22+ to reflect API evolution.*/
/*!severity: info*/
/*!minJavaVersion: 16*/
safeSubtreeMatch($node.getPatternVariable(), $o.getPatternVariable()) :: instanceof($node, "org.eclipse.jdt.core.dom.TypePattern") && instanceof($o, "org.eclipse.jdt.core.dom.TypePattern") && sourceVersionGE(22)
=> safeSubtreeMatch($node.getPatternVariable2(), $o.getPatternVariable2())
;;

/*!id: jdt.internal.codecomplete.add-timeoutmonitor*/
/*!description: Add a CompletionTimeoutProgressMonitor to cu.codeComplete() calls for internal JDT content assist.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, api-evolution*/
org.eclipse.jdt.core.ICompilationUnit.$cu.codeComplete($offset, $requestor)
=> $cu.codeComplete($offset, $requestor, new org.eclipse.jdt.internal.ui.text.CompletionTimeoutProgressMonitor())
;;

org.eclipse.jdt.core.ICompilationUnit.$cu.codeComplete($offset, $requestor, $existingMonitor)
=> $cu.codeComplete($offset, $requestor, new org.eclipse.jdt.internal.ui.text.CompletionTimeoutProgressMonitor())
;;

/*!id: jdt.internal.importname.simple-name-extraction*/
/*!description: Replaces manual simple name extraction from a qualified name with Signature.getSimpleName() for robustness.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
$qualifiedName.substring($containerName.length() + 1)
=> org.eclipse.jdt.core.Signature.getSimpleName($qualifiedName)
;;

/*!id: jdt.internal.importname.qualified-name-construction*/
/*!description: Adjusts qualified name construction in ImportName to correctly handle types from the default package (empty container name).*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
this.qualifiedName = this.containerName + "." + this.simpleName
=> this.qualifiedName = $containerName.isEmpty() ? $simpleName : $containerName + "." + $simpleName
;;

/*!id: jdt.internal.nameenvironment.super.findtype.modules.chararr-chararr*/
/*!description: Updates internal JDT NameEnvironmentWithProgress.super.findType method call to include the IModule[] modules argument for Java 9+ module system support. Assumes the enclosing method's signature has already been updated to include the $modules parameter.*/
/*!severity: info*/
/*!minJavaVersion: 9*/
super.findType($typeName, $packageName) :: sourceVersionGE(9)
=> super.findType($typeName, $packageName, $modules)
;;

